<!-- Leading space -->
<span>  
  text</span>

<!-- Trailing space -->
<span>text
    </span>

<!-- Both spaces -->
<span>
text
  </span>

<!-- Multiple words with leading space -->
<span>  text1 text2</span>

<!-- Multiple words with trailing space -->
<span>text1 text2
    </span>

<!-- With expression, leading space -->
<span>  
  → {expr}ms</span>

<!-- With expression, trailing space -->
<span>{expr}ms →  </span>

<!-- Small element -->
<small>  
  text</small>

<!-- Nested inline with boundary whitespace -->
<span>  <strong>text</strong>  
</span>

<!-- Expression at start with leading space -->
<span>  
  {expr}</span>

<!-- Expression at end with trailing space -->
<span>{expr}
    </span>
